#include <stdio.h>
#include <stdlib.h>

int max(int a, int b) {
    return a > b ? a : b;
}

int solve(int i, int j, int N, int M, int K, int A[], int B[][M], int C[][M], int dp[][K + 1]) {
    if (i == N) {
        return 0;
    }
    if (dp[i][j] != -1) {
        return dp[i][j];
    }
    int ans = -1;
    for (int k = 0; k < M; k++) {
        if (k == A[i] - 1) {
            ans = max(ans, B[i][k] + solve(i + 1, j, N, M, K, A, B, C, dp));
        } else if (j < K) {
            ans = max(ans, B[i][k] - C[i][k] + solve(i + 1, j + 1, N, M, K, A, B, C, dp));
        }
    }
    dp[i][j] = ans;
    return ans;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M, K;
        scanf("%d %d %d", &N, &M, &K);
        int A[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        int B[N][M];
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < M; j++) {
                scanf("%d", &B[i][j]);
            }
        }
        int C[N][M];
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < M; j++) {
                scanf("%d", &C[i][j]);
            }
        }
        int dp[N + 1][K + 1];
        for (int i = 0; i <= N; i++) {
            for (int j = 0; j <= K; j++) {
                dp[i][j] = -1;
            }
        }
        printf("%d\n", solve(0, 0, N, M, K, A, B, C, dp));
    }
    return 0;
}

